window.TUSDATA=window.TUSDATA||{};
TUSDATA.statesProse=TUSDATA.statesProse||{};
Object.assign(TUSDATA.statesProse,{
"01":{origin:"Mississippi Territory (1798) → Alabama Territory (1817) → statehood 1819",namedFor:"The Alabama (Albaamaha) people of the upper Alabama River; meaning debated, perhaps 'plant gatherers'",
 eras:[
  {from:1750,to:1819,text:"Homeland of the Muscogee (Creek), Choctaw, Chickasaw, and Cherokee nations. France held Mobile from 1702; Britain took the region in 1763, Spain the coast in 1783. After the Creek War, the 1814 Treaty of Fort Jackson stripped the Muscogee of some 23 million acres, igniting the 'Alabama Fever' land rush; Alabama Territory was organized in 1817 and statehood followed in 1819."},
  {from:1819,to:1865,text:"Cotton and slavery built the Black Belt; by 1860 some 435,000 Alabamians — 45 percent — were enslaved. The remaining Muscogee, Choctaw, Chickasaw, and Cherokee communities were forced west in the 1830s removals. Alabama seceded in January 1861, and Montgomery served as the Confederacy's first capital; war and emancipation then broke the plantation order."},
  {from:1865,to:1955,text:"Sharecropping and convict leasing replaced slavery, and the 1901 constitution disenfranchised Black voters and many poor whites. Birmingham, founded 1871 atop coal and iron seams, became the South's steel center. The boll weevil ravaged cotton after 1915, pushing farm families north in the Great Migration; New Deal dams on the Tennessee River and wartime plants began modernizing the state."},
  {from:1955,to:2026,text:"The Montgomery bus boycott (1955-56), the Birmingham church bombing (1963), and the Selma-to-Montgomery marches (1965) made Alabama the crucible of the civil rights movement. Huntsville's Redstone Arsenal and Marshall Space Flight Center built the rockets that carried Apollo to the Moon. Steel faded; Mercedes-Benz, Honda, and Hyundai plants and aerospace now anchor an economy still marked by rural poverty."}
 ],
 sources:["Alabama Department of Archives and History","Encyclopedia of Alabama","U.S. Census Bureau"]},
"02":{origin:"Russian America (1741-1867) → U.S. purchase 1867 → District, then Territory (1912) → statehood 1959",namedFor:"Unangan (Aleut) 'alaxsxaq' — 'the mainland, that toward which the sea is directed'",
 eras:[
  {from:1750,to:1867,text:"Homeland of Inupiat, Yup'ik, Unangan (Aleut), Alutiiq, Athabascan, Tlingit, Haida, and Tsimshian peoples. Russian fur traders, arriving after Bering's 1741 voyage, forced Unangan hunters into the sea-otter trade; disease and violence cut their population by perhaps 80 percent. The Russian-American Company ruled from Sitka after crushing Tlingit resistance in 1804. With otters depleted, Russia sold its claim to the United States in 1867 for $7.2 million."},
  {from:1867,to:1959,text:"Governed as a customs district, then territory (1912), with Native peoples long denied land title. Gold at Juneau, the Klondike routes, Nome, and Fairbanks drew stampeders; salmon canneries dominated the coast. Japan occupied Attu and Kiska in 1942, and the U.S. interned Unangan villagers in squalid camps. Wartime bases and the Alaska Highway bound the territory to the continent; statehood came in 1959."},
  {from:1959,to:1980,text:"The 1964 Good Friday earthquake, magnitude 9.2, was North America's strongest recorded. Oil found at Prudhoe Bay in 1968 changed everything: the Alaska Native Claims Settlement Act (1971) conveyed 44 million acres and $962.5 million to Native corporations, clearing the way for the 800-mile Trans-Alaska Pipeline (1977), and ANILCA (1980) protected over 100 million acres as parks and refuges."},
  {from:1980,to:2026,text:"Oil royalties fund state government and the Permanent Fund dividend paid to every resident; the 1989 Exxon Valdez spill fouled Prince William Sound. Production has declined since 1988, with fishing, tourism, and the military sharing the economy. Alaska Natives remain nearly a fifth of the population. Warming far faster than the global average, Alaska faces thawing permafrost and eroding coastal villages."}
 ],
 sources:["Alaska Historical Society","National Archives","U.S. Census Bureau"]},
"04":{origin:"Mexican Cession (1848) and Gadsden Purchase (1853) → New Mexico Territory → Arizona Territory (1863) → statehood 1912",namedFor:"Probably O'odham 'ali sonak' — 'small spring' — via Spanish 'Arizonac'",
 eras:[
  {from:1750,to:1848,text:"Homeland of the O'odham, Hopi, Dine (Navajo), Apache, Yavapai, and Colorado River peoples, heirs of the Hohokam canal builders. Spain planted missions and the Tucson presidio (1775) on O'odham land but never subdued the Apache. Mexico inherited the frontier in 1821; the United States took nearly all of it in the 1848 Mexican Cession, adding the Gadsden Purchase strip in 1853."},
  {from:1848,to:1912,text:"Arizona Territory was carved from New Mexico in 1863. In 1864 the army forced some 8,000 Navajos on the Long Walk to Bosque Redondo; survivors returned under an 1868 treaty to a reservation now the nation's largest. Apache resistance under Cochise and Geronimo ended in 1886. Copper at Bisbee and Jerome, railroads, and the 1911 Roosevelt Dam set up statehood on February 14, 1912."},
  {from:1912,to:1945,text:"The last contiguous state grew on the 'Five C's' — copper, cattle, cotton, citrus, climate. In the 1917 Bisbee Deportation, vigilantes shipped nearly 1,200 striking miners into the desert. Reclamation dams made the Salt River Valley an irrigated oasis. World War II brought airfields and POW camps, plus the Poston and Gila River internment camps for Japanese Americans, while Navajo Code Talkers served in the Pacific."},
  {from:1945,to:2026,text:"Air conditioning and cheap land ignited Sun Belt growth: Phoenix, about 65,000 people in 1940, now anchors America's fifth-largest city. The Central Arizona Project (completed 1993) lifts Colorado River water to the cities even as drought forces shortage cuts. Semiconductors — Motorola, Intel, TSMC — retirees, and tourism drive the economy; 22 federally recognized tribes hold over a quarter of the land."}
 ],
 sources:["Arizona Historical Society","Library of Congress","U.S. Census Bureau"]},
"05":{origin:"Louisiana Purchase (1803) → Missouri Territory → Arkansas Territory (1819) → statehood 1836",namedFor:"French rendering of 'Akansa,' an Algonquian name for the Quapaw — the 'downstream people'",
 eras:[
  {from:1750,to:1803,text:"Homeland of the Quapaw along the Mississippi and Arkansas rivers, with Caddo towns in the southwest and Osage hunting ranges across the north. France's Arkansas Post (founded 1686) remained a small fur-trade outpost; Spain held the west bank after 1763. Native populations, already thinned by European disease, faced new pressure when the Louisiana Purchase brought American sovereignty in 1803."},
  {from:1803,to:1861,text:"Arkansas Territory was organized in 1819. Treaties of 1818 and 1824 dispossessed the Quapaw, who were removed to Indian Territory; the Caddo ceded their lands in 1835, and Trail of Tears routes crossed the state in the 1830s. Statehood came in 1836. Cotton and slavery spread through the Delta lowlands — enslaved people were a quarter of the population by 1860 — while Ozark hill farms stayed small."},
  {from:1861,to:1957,text:"Arkansas seceded in May 1861; war and Reconstruction gave way to sharecropping, disenfranchisement, and violence, including the 1919 Elaine Massacre of Black sharecroppers. Timber companies cut the pine and hardwood forests, and the 1927 Mississippi flood put much of the Delta underwater. Rice, introduced on the Grand Prairie around 1900, eventually made Arkansas the nation's leading producer."},
  {from:1957,to:2026,text:"The 1957 Central High crisis in Little Rock, where federal troops escorted nine Black students past a segregationist governor, became a civil rights landmark. Mechanized cotton pushed workers north in the Great Migration. Home-grown giants — Walmart of Bentonville, Tyson Foods, J.B. Hunt — now power a northwest Arkansas boom, while the Delta remains among America's poorest regions."}
 ],
 sources:["Encyclopedia of Arkansas","Arkansas State Archives","U.S. Census Bureau"]},
"06":{origin:"Spanish Alta California (1769) → Mexican rule (1821) → Mexican Cession (1848) → statehood 1850, with no territorial stage",namedFor:"A mythical island in a Spanish romance (c. 1510) ruled by Queen Calafia",
 eras:[
  {from:1750,to:1848,text:"The most densely settled Indigenous region north of Mexico — perhaps 300,000 people speaking scores of languages, from Yurok and Pomo to Chumash and Kumeyaay. Spain's 21 missions (begun 1769) conscripted Native labor; disease and disruption killed tens of thousands. Mexico secularized the missions in the 1830s, parceling the land into ranchos, then ceded California to the United States in 1848."},
  {from:1848,to:1900,text:"Gold found at Sutter's Mill in January 1848 drew some 300,000 fortune seekers; California entered the Union free in 1850. What followed was genocide: state-funded militias, bounties, and legalized indenture killed and enslaved California Indians, whose population collapsed from roughly 150,000 in 1848 to about 16,000 by 1900. Hydraulic mining choked rivers; the 1869 transcontinental railroad, built largely by Chinese laborers, tied the state east."},
  {from:1900,to:1945,text:"The 1906 earthquake and fire destroyed San Francisco. Los Angeles took Owens Valley water by aqueduct (1913), oil derricks and Hollywood studios multiplied, and irrigated Central Valley agribusiness drew Dust Bowl migrants through the 1930s. World War II brought shipyards, aircraft plants, and mass migration — and the forced removal of 120,000 Japanese Americans to camps such as Manzanar and Tule Lake."},
  {from:1945,to:2026,text:"Cold War aerospace, freeways, and suburbs powered growth; California's population passed New York's by 1963. Silicon Valley made the state the center of global technology, and Central Valley farms grow over a third of America's vegetables and most of its fruits and nuts. Now about 39 million people and the nation's largest state economy, California confronts drought, wildfire, and housing costs; in 2019 the state formally apologized for the genocide of Native peoples."}
 ],
 sources:["California State Archives","Library of Congress","U.S. Census Bureau"]},
"08":{origin:"Louisiana Purchase (1803) and Mexican Cession (1848) → Colorado Territory (1861) → statehood 1876",namedFor:"Spanish 'colorado' — 'reddish' — for the silt-red Colorado River",
 eras:[
  {from:1750,to:1858,text:"Ute bands held the mountains; Cheyenne, Arapaho, Comanche, and Kiowa ranged the plains on horseback. Spain, then Mexico, claimed the south and west, while the Louisiana Purchase (1803) put the eastern plains on American maps drawn by Pike and Long. The 1851 Fort Laramie treaty recognized Cheyenne and Arapaho territory that gold would soon override."},
  {from:1858,to:1876,text:"The 1858-59 Pikes Peak gold rush poured tens of thousands of miners onto Cheyenne and Arapaho land; Colorado Territory followed in 1861. At Sand Creek on November 29, 1864, territorial cavalry massacred some 230 Cheyenne and Arapaho people, mostly women, children, and elders, at a peaceful camp. The tribes were driven to Indian Territory; statehood arrived in 1876, the centennial year."},
  {from:1876,to:1945,text:"Leadville silver and Cripple Creek gold built fortunes until the 1893 silver crash. After the 1879 Meeker incident, the Utes were forced from the Western Slope to Utah reservations in 1881, keeping only southern Colorado lands. Coal-country conflict turned deadly at Ludlow in 1914, when militia gunfire and fire killed strikers' wives and children. Sugar beets, cattle, and dryland wheat spread — until Dust Bowl storms buried the southeast."},
  {from:1945,to:2026,text:"Cold War installations — NORAD beneath Cheyenne Mountain, the Air Force Academy, federal labs — and postwar migration remade the Front Range. Transmountain diversions carry Colorado River water east to farms and fast-growing cities. Skiing at Aspen and Vail built a tourism economy; voters legalized recreational cannabis in 2012, a national first shared with Washington. Denver anchors a tech-heavy metro of about 3 million."}
 ],
 sources:["History Colorado","U.S. Census Bureau"]},
"09":{origin:"One of the thirteen original colonies (settled 1630s); fifth to ratify the Constitution, 1788",namedFor:"Algonquian 'Quinnehtukqut' — beside the long tidal river",
 eras:[
  {from:1750,to:1788,text:"Long the homeland of the Pequot, Mohegan, Quinnipiac, and Paugussett — shattered by the 1637 Pequot War and confined to small reservations, among the oldest in America. The Puritan colony, self-governing under its 1662 charter, farmed the Connecticut Valley and supplied Washington's armies so reliably it was called the Provisions State. In 1788 it ratified the Constitution fifth, after brokering the Connecticut Compromise."},
  {from:1788,to:1860,text:"Thin soils pushed Yankees west — Connecticut claimed Ohio's Western Reserve until 1800 — while ingenuity industrialized the state: Eli Whitney's arms works, Waterbury brass, Terry clocks, Hartford insurance offices. Slavery ended slowly under gradual emancipation, fully abolished only in 1848. Textile and metal mills drew Irish immigrants, and river towns became factory cities."},
  {from:1860,to:1945,text:"Connecticut armed the Union — Colt revolvers, Sharps rifles, Winchester repeaters — and its precision industries drew Italian, Polish, and French Canadian workers. Hartford led the nation in insurance. Through the World Wars the state built submarines at Groton, aircraft engines at Pratt and Whitney, and Sikorsky helicopters, a dense arsenal of American industry."},
  {from:1945,to:2026,text:"Defense contracts and suburbs sustained prosperity; hedge funds settled Fairfield County while Hartford, Bridgeport, and New Haven struggled with deindustrialization, leaving stark wealth gaps. Federal recognition brought the Mashantucket Pequot's Foxwoods (1992) and the Mohegan Sun (1996), for a time the world's largest casinos. Insurance, finance, submarines, and jet engines still anchor one of America's richest states."}
 ],
 sources:["Connecticut State Library","U.S. Census Bureau"]},
"10":{origin:"New Sweden (1638) → Dutch, then English rule → the 'Three Lower Counties' of Pennsylvania → first state to ratify, 1787",namedFor:"The Delaware River and Bay, named for Virginia governor Thomas West, Lord De La Warr",
 eras:[
  {from:1750,to:1787,text:"Lenape homeland along the river Europeans renamed the Delaware; most Lenape, pressed by colonists and epidemics, had been pushed west by mid-century, while Nanticoke families persisted near the bay. Settled by Swedes (1638), seized by the Dutch, then the English, the 'Three Lower Counties' shared Pennsylvania's governor but kept their own assembly. On December 7, 1787, Delaware ratified the Constitution first."},
  {from:1787,to:1865,text:"Brandywine flour mills and the du Pont gunpowder works (1802) began industrialization; peaches and grain covered the south. A slave state that never seceded, Delaware saw slavery wither — over 90 percent of Black Delawareans were free by 1860 — yet its legislature rejected the Thirteenth Amendment, and slavery ended there only with national ratification in December 1865."},
  {from:1865,to:1950,text:"Jim Crow laws segregated schools and polls despite the state's Union record. DuPont grew from explosives into a chemical empire, inventing nylon in the late 1930s and bankrolling Wilmington. The 1899 General Corporation Law and the Court of Chancery began drawing companies to incorporate in Delaware, and broiler chickens — a 1920s Sussex County innovation — became the farm economy's mainstay."},
  {from:1950,to:2026,text:"Delaware school segregation cases fed directly into Brown v. Board of Education (1954). The 1981 Financial Center Development Act drew credit-card banks to Wilmington. Today well over a million business entities, including most Fortune 500 firms, are chartered here for the corporate courts. Chemicals, banking, and chicken farming coexist in the second-smallest state, longtime home of Joe Biden."}
 ],
 sources:["Delaware Public Archives","Delaware Historical Society","U.S. Census Bureau"]},
"11":{origin:"Ceded by Maryland and Virginia under the Residence Act (1790); federal capital from 1800 — a district, never a state",namedFor:"Columbia, a poetic name for America honoring Columbus; the city honors George Washington",
 eras:[
  {from:1750,to:1800,text:"The Nacotchtank (Anacostans) and Piscataway lived at the Potomac-Anacostia confluence until disease and colonial pressure scattered them, many merging with neighboring nations by the early 1700s. Tobacco farms and the ports of Georgetown and Alexandria occupied the site Congress chose under the 1790 Residence Act — a ten-mile square ceded by Maryland and Virginia. The government arrived from Philadelphia in 1800."},
  {from:1800,to:1862,text:"British troops burned the Capitol and White House in 1814. The city grew slowly, a marshy capital where enslaved laborers built federal buildings and slave pens operated within sight of the Capitol until the Compromise of 1850 banned the trade. Virginia's portion, including Alexandria, was retroceded in 1846. In April 1862 Congress emancipated the District's enslaved people, months before the Emancipation Proclamation."},
  {from:1862,to:1973,text:"A refuge for freedpeople, Washington built Howard University and a strong Black middle class despite congressionally imposed segregation; residents lost local self-government entirely in 1874. The federal city swelled through the New Deal and World Wars, becoming majority-Black 'Chocolate City' by 1957. The 23rd Amendment (1961) granted presidential electors; riots after Dr. King's 1968 assassination scarred whole corridors."},
  {from:1973,to:2026,text:"The 1973 Home Rule Act restored an elected mayor and council, though Congress still reviews the District's laws and budget. Population fell, then rebounded toward 700,000 amid gentrification that ended the Black majority around 2011. License plates protest 'Taxation Without Representation'; statehood bills passed the House in 2020 and 2021 but stalled in the Senate, leaving residents without voting members of Congress."}
 ],
 sources:["National Archives","Library of Congress","U.S. Census Bureau"]},
"12":{origin:"Spanish La Florida (1513) → British 1763 → Spanish 1783 → ceded to the U.S. 1819 → Florida Territory (1822) → statehood 1845",namedFor:"Spanish 'La Florida,' for Easter's 'Pascua Florida' — feast of flowers — at Ponce de Leon's 1513 landing",
 eras:[
  {from:1750,to:1821,text:"The Apalachee, Timucua, and Calusa had been nearly annihilated by epidemics and English-backed slave raids by the 1760s; Creek migrants filled the void, becoming the Seminoles, joined by escaped enslaved Africans. Spain, Britain (1763-83), and Spain again traded the peninsula. Andrew Jackson's 1818 invasion — the First Seminole War — pushed Spain to cede Florida in the 1819 Adams-Onis Treaty."},
  {from:1821,to:1865,text:"Territorial Florida (1822) fought the Second Seminole War (1835-42), the costliest of America's Indian wars; Osceola was seized under a truce flag, and most Seminoles were shipped to Indian Territory. A few hundred withdrew into the Everglades, never surrendering. Cotton plantations spread across Middle Florida — nearly half the population was enslaved at statehood in 1845 — and Florida seceded in January 1861."},
  {from:1865,to:1945,text:"Flagler's and Plant's railroads opened the peninsula to tourists, citrus, and phosphate; Cuban cigar makers built Ybor City. Drainage canals attacked the Everglades. The 1920s land boom collapsed amid the 1926 Miami hurricane and the 1928 Okeechobee storm, which drowned some 2,500 people, most of them Black farmworkers. World War II filled the state with airfields and training bases."},
  {from:1945,to:2026,text:"Air conditioning, Social Security, and cheap flights made Florida a magnet: retirees, Cuban exiles after 1959, and Disney World (1971) drove growth past 23 million people, now third in the nation. Kennedy Space Center launched the Moon missions. The unconquered Seminole Tribe pioneered high-stakes Indian gaming in 1979. Hurricanes and rising seas now shadow the coasts the economy depends on."}
 ],
 sources:["Florida Historical Society","State Library and Archives of Florida","U.S. Census Bureau"]},
"13":{origin:"One of the thirteen original colonies (founded 1733); fourth to ratify the Constitution, 1788",namedFor:"King George II of Great Britain",
 eras:[
  {from:1750,to:1788,text:"Muscogee (Creek) nations held the interior and Cherokee towns the mountains when Oglethorpe's colony (1733) — a debtors' refuge and military buffer that briefly banned slavery — took root at Savannah. The ban fell in 1751, and rice plantations worked by enslaved Africans spread along the coast. Georgia ratified the Constitution fourth, in January 1788."},
  {from:1788,to:1838,text:"Eli Whitney's cotton gin (1793) ignited a plantation boom that demanded Native land; treaties and fraud stripped the Muscogee by 1827. Gold found near Dahlonega in 1828-29 doomed the Cherokee: Georgia defied the Supreme Court's Worcester ruling, and after the disputed Treaty of New Echota, troops drove some 16,000 Cherokees west in 1838 on the Trail of Tears. About 4,000 died."},
  {from:1838,to:1865,text:"Cotton made Georgia the heart of the Deep South; by 1860 some 462,000 people — 44 percent of Georgians — were enslaved. The state seceded in January 1861. Sherman's armies took Atlanta in September 1864 and cut a sixty-mile-wide swath to Savannah in the March to the Sea, breaking the Confederacy's logistics and, with emancipation, its labor system."},
  {from:1865,to:1945,text:"Reconstruction's promise collapsed into convict leasing, sharecropping, lynching, and the 1906 Atlanta race riot; a 1908 amendment disenfranchised Black voters. Atlanta rebuilt as the 'New South' rail hub while textile mills spread through the Piedmont. The boll weevil wrecked cotton after 1915, driving the Great Migration north. World War II brought Fort Benning's expansion and the Bell bomber plant at Marietta."},
  {from:1945,to:2026,text:"Atlanta, home of Martin Luther King Jr., styled itself 'the city too busy to hate' and became the civil rights movement's headquarters. Coca-Cola, Delta, CNN, and the 1996 Olympics built a global metro; Hartsfield-Jackson ranks as the world's busiest airport. Film studios, ports, and in-migration pushed Georgia past 11 million people and into battleground-state politics."}
 ],
 sources:["Georgia Historical Society","New Georgia Encyclopedia","U.S. Census Bureau"]},
"15":{origin:"Unified Kingdom of Hawai'i (1810) → 1893 overthrow → Republic → U.S. annexation 1898 → Territory 1900 → statehood 1959",namedFor:"Hawaiian 'Hawai'i,' echoing Hawaiki, the ancestral Polynesian homeland",
 eras:[
  {from:1750,to:1810,text:"Native Hawaiians, descendants of Polynesian voyagers, had built a complex civilization of chiefdoms, fishponds, and irrigated taro when Captain Cook arrived in 1778. Introduced diseases began a demographic catastrophe that would kill the great majority of Hawaiians within a century. Using Western arms, Kamehameha I conquered rival chiefs and unified the islands as the Kingdom of Hawai'i by 1810."},
  {from:1810,to:1893,text:"The kingdom won recognition from world powers while missionaries arrived (1820) and the 1848 Mahele privatized land, easing its passage to foreigners. American-owned sugar plantations imported Chinese, Japanese, Portuguese, and Filipino labor. The 1887 'Bayonet Constitution' stripped the monarchy's power; on January 17, 1893, planters backed by U.S. Marines overthrew Queen Lili'uokalani."},
  {from:1893,to:1959,text:"The United States annexed Hawai'i in 1898 over mass Native petitions and made it a territory in 1900; sugar's 'Big Five' firms dominated politics, and Hawaiian language was suppressed in schools. Japan's December 7, 1941 attack on Pearl Harbor brought years of martial law — and the decorated Japanese American 442nd Regiment. Labor organizing broke oligarchy rule, and statehood followed in 1959."},
  {from:1959,to:2026,text:"Jet tourism replaced sugar and pineapple, drawing about ten million visitors a year; the military holds large tracts of O'ahu. A Hawaiian renaissance revived language, hula, and voyaging, and in 1993 the United States formally apologized for the overthrow, fueling an ongoing sovereignty movement. Housing costs push Native Hawaiians outward; the 2023 Lahaina fire killed 102 people."}
 ],
 sources:["Hawai'i State Archives","Library of Congress","U.S. Census Bureau"]},
"16":{origin:"Oregon Country (joint U.S.-British occupation to 1846) → Oregon and Washington territories → Idaho Territory (1863) → statehood 1890",namedFor:"A coined word falsely promoted as Shoshone for 'gem of the mountains'",
 eras:[
  {from:1750,to:1846,text:"Homeland of the Nimiipuu (Nez Perce), Shoshone, Bannock, Coeur d'Alene, Kootenai, and Northern Paiute, who fished Snake River salmon and rode to buffalo country. Lewis and Clark crossed Nez Perce lands in 1805, followed by fur brigades and Oregon Trail wagons along the Snake. Britain and the United States jointly held the Oregon Country until the 1846 boundary treaty."},
  {from:1846,to:1890,text:"Gold rushes from 1860 brought miners onto Native land; Idaho Territory followed in March 1863. Weeks earlier, U.S. soldiers had massacred hundreds of Northwestern Shoshone men, women, and children at Bear River — among the deadliest slaughters of Native people in American history. An 1863 treaty cut the Nez Perce reservation by 90 percent; Chief Joseph's band fought and fled 1,170 miles in the 1877 war. Statehood came in 1890."},
  {from:1890,to:1949,text:"Coeur d'Alene silver and lead mines saw explosive labor wars in 1892 and 1899, bringing federal troops and martial law. Carey Act and Reclamation canals turned the arid Snake River Plain into irrigated farmland — the foundation of the famous potato crop. Timber companies cut the white pine belt, and the 1910 'Big Burn' incinerated some three million acres."},
  {from:1949,to:2026,text:"The National Reactor Testing Station (1949, now Idaho National Laboratory) produced the world's first nuclear-generated electricity in 1951. Irrigated agribusiness — potatoes, sugar beets, dairy — plus Micron's Boise semiconductors and recreation drive one of the nation's fastest-growing states. Five federally recognized tribes exercise treaty rights; the Aryan Nations compound at Hayden Lake was bankrupted by lawsuit in 2000."}
 ],
 sources:["Idaho State Historical Society","U.S. Census Bureau"]},
"17":{origin:"French Illinois Country → British 1763 → Northwest Territory (1787) → Illinois Territory (1809) → statehood 1818",namedFor:"French rendering of the Illiniwek (Illinois) confederation's name",
 eras:[
  {from:1750,to:1818,text:"Homeland of the Illinois Confederation — heirs to Cahokia, the great pre-Columbian city near modern St. Louis — with Potawatomi, Kickapoo, Sauk, and Meskwaki nations. French villages like Kaskaskia farmed the American Bottom under France, then Britain (1763), then Virginia's George Rogers Clark (1778). Organized under the Northwest Ordinance's slavery ban, Illinois reached statehood in 1818, though Black indentured servitude persisted for decades."},
  {from:1818,to:1871,text:"The 1832 Black Hawk War crushed Sauk resistance, and the 1833 Treaty of Chicago removed the Potawatomi west, emptying northern Illinois for settlers. The Illinois and Michigan Canal (1848) and railroads made Chicago the interior's great market; John Deere's steel plow broke the prairie. Illinois sent Lincoln to the presidency and about 250,000 men to the Union army. In 1871 fire leveled Chicago."},
  {from:1871,to:1945,text:"Chicago rebuilt skyward — birthplace of the skyscraper — its stockyards, steel mills, and rail yards drawing European immigrants and, in the Great Migration, Black Southerners; the 1919 race riot killed 38. Haymarket (1886) and Pullman (1894) made the city a crucible of American labor conflict. Downstate, corn, coal, and factory towns like Peoria and Moline built the farm-machinery industry."},
  {from:1945,to:2026,text:"Postwar Chicago confined Black migrants to segregated high-rise public housing while suburbs boomed and O'Hare became a global hub. Deindustrialization closed the stockyards (1971) and most steelworks. The metro pivoted to finance, futures exchanges, and services; downstate stayed agricultural. The population, about 12.8 million in 2020, has since slipped amid fiscal strain, yet Illinois remains the Midwest's economic anchor."}
 ],
 sources:["Illinois State Archives","Chicago History Museum","U.S. Census Bureau"]},
"18":{origin:"Northwest Territory (1787) → Indiana Territory (1800) → statehood 1816",namedFor:"'Land of the Indians' — a Latinate coinage for the territory",
 eras:[
  {from:1750,to:1816,text:"Miami, Potawatomi, Shawnee, Lenape, and Wea peoples held the Wabash country, long contested by France and Britain. After the 1795 Treaty of Greenville opened land cessions, Tecumseh and the Prophet built pan-Indian resistance at Prophetstown until Harrison's army burned it following Tippecanoe (1811). Indiana Territory (1800), its slavery workarounds rejected, entered the Union free in 1816."},
  {from:1816,to:1865,text:"Treaty by treaty the state was cleared: in 1838 militia marched 859 Potawatomi to Kansas on the Trail of Death — more than 40 died — and canal boats carried the Miami west in 1846, though about half that nation stayed on family reserves. Canal building bankrupted the state by 1841; railroads followed. Nearly 200,000 Hoosiers fought for the Union."},
  {from:1865,to:1945,text:"Natural-gas discoveries in the 1880s fueled glass and early auto industries; Studebaker built South Bend, and U.S. Steel raised Gary from the dunes in 1906. The first Indianapolis 500 ran in 1911. The 1920s Klan captured state politics — roughly a quarter-million members — before scandal broke it in 1925. Wartime steel, ordnance, and engines ran at full tilt."},
  {from:1945,to:2026,text:"Indiana remained America's most manufacturing-intensive state: Calumet steel, Elkhart RVs, Columbus diesels, Lilly pharmaceuticals in Indianapolis. Gary's decline after 1970 was as steep as its rise, the city losing over half its people. Corn, soybeans, and hogs dominate the countryside; Indianapolis reinvented itself around sports and life sciences, and the Pokagon Potawatomi regained federal recognition in 1994."}
 ],
 sources:["Indiana Historical Society","Indiana State Library","U.S. Census Bureau"]},
"19":{origin:"Louisiana Purchase (1803) → Michigan and Wisconsin territories → Iowa Territory (1838) → statehood 1846",namedFor:"The Ioway (Baxoje) nation, whose name French traders wrote 'Aiouez'",
 eras:[
  {from:1750,to:1833,text:"Homeland of the Ioway (Baxoje), with Sauk and Meskwaki towns along the Mississippi and Dakota bands in the northwest — a land shaped by the Effigy Mounds builders. France and Spain claimed but barely touched it, and it passed in the 1803 Louisiana Purchase. After the 1832 Black Hawk War, the United States forced the Sauk and Meskwaki to cede the eastern 'Black Hawk Purchase,' opened to settlers in 1833."},
  {from:1833,to:1870,text:"Settlement raced west; Iowa Territory (1838) became a free state in 1846. The Ioway were removed to Kansas, but Meskwaki families pooled treaty money in 1857 to buy land at Tama — a self-purchased settlement they still govern. Steamboats, then the first railroads, moved wheat and hogs; by 1870 the prairie was being plowed into the emerging Corn Belt."},
  {from:1870,to:1945,text:"Railroads gridded the state into 99 counties of family farms; more than 99 percent of the tallgrass prairie ultimately went under the plow, and drained wetlands became some of Earth's richest cropland. Corn, hogs, and cattle feeding defined the economy. Farm depression struck through the 1920s and 1930s, spurring Farm Holiday strikes, before wartime demand and hybrid seed corn restored prosperity."},
  {from:1945,to:2026,text:"Mechanization emptied the countryside, and the 1980s farm crisis foreclosed thousands of farms and shrank small towns. Iowa now leads the nation in corn, hogs, eggs, and ethanol, its meatpacking towns drawing Latino and other immigrant workers. Des Moines grew on insurance and finance. From 1972 to 2020 Iowa's caucuses opened presidential campaigns; about 3.2 million people live here."}
 ],
 sources:["State Historical Society of Iowa","U.S. Census Bureau"]},
"20":{origin:"Louisiana Purchase (1803) → designated Indian country → Kansas Territory (1854) → statehood 1861",namedFor:"The Kanza (Kaw) people — 'people of the south wind'",
 eras:[
  {from:1750,to:1854,text:"The Kanza (Kaw) and Osage held the eastern valleys; Pawnee, Cheyenne, Arapaho, Comanche, and Kiowa hunted bison across the plains. After the Louisiana Purchase (1803), the United States designated Kansas 'Indian country' and relocated Shawnee, Delaware, Potawatomi, and other eastern nations there — promises shattered when the 1854 Kansas-Nebraska Act opened the territory to white settlement under popular sovereignty."},
  {from:1854,to:1874,text:"'Bleeding Kansas' pitted free-state and proslavery settlers in guerrilla war — Lawrence sacked, John Brown's Pottawatomie killings — a prelude to national conflict. Kansas entered the Union free in January 1861; Quantrill's raiders burned Lawrence in 1863, killing at least 150. Railroads and cattle towns like Abilene and Dodge City followed, while hide hunters annihilated the bison and treaties pushed the Plains nations and the Kaw south."},
  {from:1874,to:1945,text:"Mennonite immigrants' Turkey Red winter wheat (1874) suited the dry plains, making Kansas the nation's breadbasket. Black 'Exodusters' fleeing the post-Reconstruction South founded Nicodemus in 1877. Populist revolt swept the 1890s. Plowed-up shortgrass turned to black blizzards in the 1930s Dust Bowl, while Wichita's Cessna, Beechcraft, and Stearman plants — the 'Air Capital' — mass-produced World War II bombers."},
  {from:1945,to:2026,text:"Topeka's Brown v. Board of Education (1954) struck down school segregation nationwide. Center-pivot irrigation from the Ogallala Aquifer pushed corn and feedlots onto the High Plains, drawing down water that recharges slowly if at all. Wheat, beef, and aircraft still lead; meatpacking towns like Garden City and Dodge City are now majority-minority, and about 2.9 million people call Kansas home."}
 ],
 sources:["Kansas Historical Society","Library of Congress","U.S. Census Bureau"]},
"21":{origin:"Virginia's trans-Appalachian Kentucky County (1776) → separated by consent → statehood 1792",namedFor:"From an Iroquoian word, often glossed 'meadowland'; the exact origin is uncertain",
 eras:[
  {from:1750,to:1792,text:"Shawnee, Cherokee, and Chickasaw peoples hunted and contested the Bluegrass, with Shawnee towns along the Ohio. After the disputed 1775 Sycamore Shoals purchase, Boone's road through Cumberland Gap funneled settlers into Virginia's Kentucky County, igniting years of border warfare with Shawnee defenders. In 1792 Kentucky became the fifteenth state — the first west of the Appalachians."},
  {from:1792,to:1865,text:"Hemp, tobacco, and thoroughbreds grew on enslaved labor, and Louisville became a major slave-trading center for the trade 'down the river.' The 1818 Jackson Purchase bought Chickasaw claims to the west. Henry Clay brokered the Union's great compromises. Kentucky declared neutrality in 1861, then held for the Union while sending sons to both armies; slavery ended only with the Thirteenth Amendment in December 1865."},
  {from:1865,to:1945,text:"Tobacco patches and the Black Patch wars (1904-09), bourbon distilleries, and horse farms defined the countryside; Jim Crow ruled the towns. Railroads opened eastern Kentucky's coal seams, binding Appalachian counties to company towns and the bloody Harlan County strikes of the 1930s. Fort Knox began storing the nation's gold in 1937, and wartime demand ran the mines full out."},
  {from:1945,to:2026,text:"Mechanization and strip mining cut coal employment for decades before Appalachian mining collapsed outright in the 2010s, deepening regional poverty and out-migration. Toyota's Georgetown plant (opened 1988), the Corvette works at Bowling Green, and UPS's Louisville air hub rebuilt the economy, and a global bourbon boom filled more than 12 million aging barrels. About 4.5 million people live here."}
 ],
 sources:["Kentucky Historical Society","U.S. Census Bureau"]},
"22":{origin:"French La Louisiane (1682) → Spanish 1762 → French 1800 → Louisiana Purchase 1803 → Territory of Orleans → statehood 1812",namedFor:"King Louis XIV of France, honored by La Salle's 'La Louisiane' (1682)",
 eras:[
  {from:1750,to:1803,text:"Caddo, Choctaw, Chitimacha, Houma, and Tunica peoples lived along the rivers; France had already destroyed the Natchez in 1731, selling survivors into slavery. New Orleans (founded 1718) ran on the labor of enslaved Africans under the Code Noir. Acadian refugees expelled from Nova Scotia — ancestors of the Cajuns — settled the bayous under Spain, which ruled from 1762 until Napoleon sold the colony to the United States in 1803."},
  {from:1803,to:1865,text:"Statehood came in 1812, civil law intact. Sugar and cotton plantations made the lower Mississippi brutally profitable: New Orleans became the nation's largest slave market, and the 1811 German Coast uprising, the largest revolt of enslaved people in U.S. history, was crushed with beheadings. Union forces took New Orleans in April 1862, and slavery collapsed during the war."},
  {from:1865,to:1945,text:"Reconstruction brought Black officeholding and white terror — the 1873 Colfax Massacre killed as many as 150 Black defenders, and Plessy v. Ferguson (1896), a New Orleans test case, blessed segregation. Jazz rose from the city's Black neighborhoods. The 1927 flood displaced hundreds of thousands, Huey Long's machine built roads and schools autocratically, and oil drilling spread across the coast."},
  {from:1945,to:2005,text:"Petrochemical plants lined the river between Baton Rouge and New Orleans — a corridor residents call Cancer Alley — while offshore rigs marched into the Gulf. Levees and canals starved the delta of sediment: Louisiana has lost about 2,000 square miles of coast since the 1930s. Civil rights battles desegregated schools; the Chitimacha, Coushatta, Tunica-Biloxi, and Houma pressed for recognition."},
  {from:2005,to:2026,text:"Hurricane Katrina's levee failures flooded 80 percent of New Orleans on August 29, 2005, killing more than 1,300 people in Louisiana and scattering its population; recovery remade — and gentrified — the city. The 2010 Deepwater Horizon spill fouled the coast. A $50 billion coastal master plan races subsidence and rising seas as communities like Isle de Jean Charles relocate inland."}
 ],
 sources:["Louisiana State Museum","Library of Congress","U.S. Census Bureau"]},
"23":{origin:"District of Maine within Massachusetts → separated as a free state under the Missouri Compromise → statehood 1820",namedFor:"Uncertain — perhaps nautical 'the main(land),' perhaps the French province of Maine",
 eras:[
  {from:1750,to:1820,text:"Homeland of the Wabanaki Confederacy — Penobscot, Passamaquoddy, Maliseet, Mi'kmaq, and Abenaki — who endured a century of Anglo-French wars, scalp bounties, and land loss, holding only small reservations by 1800. Massachusetts governed the District of Maine; Britain occupied its eastern coast in 1814. Separation sentiment prevailed, and Maine entered the Union free in 1820 as the Missouri Compromise's northern half."},
  {from:1820,to:1900,text:"The Webster-Ashburton Treaty (1842) settled the disputed New Brunswick border after the bloodless Aroostook War. White pine made Bangor a world lumber port; yards from Kittery to Bath launched wooden ships, and quarries, ice houses, and lime kilns worked the coast. Textile mills at Lewiston and Biddeford drew French Canadian families south from Quebec."},
  {from:1900,to:1980,text:"Pulp and paper companies came to own much of the northern forest; Aroostook County led the nation in potatoes, and lobstering and sardine canneries sustained the coast. Summer colonies grew into Acadia National Park (1919) and a tourism economy. Bath Iron Works built destroyers through both World Wars. In 1980 the Penobscot and Passamaquoddy won an $81.5 million land-claims settlement."},
  {from:1980,to:2026,text:"Paper mills closed one after another after 2000, hollowing the mill towns; lobster, boosted by a warming Gulf of Maine, became the fishery's mainstay even as the waters keep heating. Tourism, boatbuilding, and Bath's destroyers anchor the coast. The nation's oldest state by median age, Maine has drawn remote workers and immigrants — Lewiston's Somali community among them."}
 ],
 sources:["Maine Historical Society","Maine State Archives","U.S. Census Bureau"]},
"24":{origin:"One of the thirteen original colonies (chartered 1632, settled 1634); seventh to ratify the Constitution, 1788",namedFor:"Queen Henrietta Maria, wife of England's Charles I",
 eras:[
  {from:1750,to:1788,text:"Piscataway, Nanticoke, and Susquehannock homelands became tobacco country; many Piscataway had withdrawn northward by 1700, while Nanticoke communities persisted on the Eastern Shore. The Calverts' colony, founded 1634 as a Catholic refuge, ran on enslaved African labor. Mason and Dixon fixed the Pennsylvania line (1763-67). Maryland ratified the Constitution seventh in 1788 and soon ceded land for the federal district."},
  {from:1788,to:1864,text:"Baltimore boomed on flour, shipping, and the nation's first major railroad, the B&O (1828); Fort McHenry's 1814 defense inspired the national anthem. Slavery dominated southern counties and the Eastern Shore, where Frederick Douglass and Harriet Tubman were born enslaved, yet by 1860 half of Black Marylanders were free. A Union slave state, Maryland saw Antietam's carnage and abolished slavery itself on November 1, 1864."},
  {from:1864,to:1945,text:"Immigrant Baltimore shucked oysters and canned vegetables; Chesapeake oyster harvests peaked in the 1880s, then collapsed from overfishing. Sparrows Point grew into one of the world's largest steelworks, and Johns Hopkins pioneered the research university and modern medicine. Jim Crow segregated the state while Baltimore's NAACP fought early battles; the World Wars swelled shipyards and aircraft plants."},
  {from:1945,to:2026,text:"Federal Washington's growth remade Maryland: NIH, NSA at Fort Meade, Goddard, and contractor suburbs made it among the nation's wealthiest states. Baltimore lost industry and population — the 1968 riots and 2015 Freddie Gray unrest marked its struggles, and the Key Bridge collapsed in 2024. Biotech, cybersecurity, and Chesapeake restoration define the agenda; the Piscataway won state recognition in 2012."}
 ],
 sources:["Maryland State Archives","Maryland Center for History and Culture","U.S. Census Bureau"]},
"25":{origin:"One of the thirteen original colonies (Plymouth 1620, Massachusetts Bay 1630); sixth to ratify, 1788",namedFor:"The Massachusett people — 'at the great hill,' the Blue Hills south of Boston",
 eras:[
  {from:1750,to:1788,text:"Homeland of the Massachusett, Wampanoag, Nipmuc, and Pocumtuck, devastated by the 1616-19 epidemic and King Philip's War (1675-76); Wampanoag communities endured at Mashpee and Aquinnah. Boston led resistance to Britain — the Massacre, the Tea Party, Lexington and Concord. Court rulings in the Quock Walker cases (1781-83) effectively ended slavery, and Massachusetts, then including Maine, ratified the Constitution sixth in 1788 after Shays' Rebellion."},
  {from:1788,to:1860,text:"Maritime wealth funded America's industrial revolution: Lowell's textile mills (1820s) hired Yankee 'mill girls,' then Irish famine refugees; New Bedford led global whaling; Lynn made shoes. Maine was set off as a free state in 1820. Boston became the capital of abolitionism — Garrison's Liberator, Douglass's speeches — and of reform movements from public schools to women's rights."},
  {from:1860,to:1950,text:"Immigrants — Irish, Italian, French Canadian, Jewish, Portuguese — powered mills that made Massachusetts an industrial giant; Lawrence's 1912 'Bread and Roses' strike rallied 25,000 workers. The state sent the Union some 150,000 men, including the famed Black 54th Regiment. After the 1920s, textiles and shoes fled south, hollowing the mill cities even as universities and hospitals grew."},
  {from:1950,to:2026,text:"Route 128 electronics, then Kendall Square biotech, turned university research into the economic engine; Harvard, MIT, and more than 100 colleges anchor it. Boston's 1970s school-busing crisis exposed deep racial fault lines. In 2004 Massachusetts became the first state with legal same-sex marriage, and the Mashpee Wampanoag regained federal recognition in 2007. Health care, education, and tech sustain high incomes — and high costs."}
 ],
 sources:["Massachusetts Historical Society","Library of Congress","U.S. Census Bureau"]},
"26":{origin:"French fur country → British 1763 → Northwest Territory (1787) → Michigan Territory (1805) → statehood 1837",namedFor:"Ojibwe 'mishigami' — 'great water'",
 eras:[
  {from:1750,to:1837,text:"Anishinaabe homeland — Ojibwe, Odawa, and Potawatomi, the Three Fires Confederacy. French Detroit (1701) ran the fur trade; Pontiac's 1763 uprising besieged the British there. U.S. control came in 1796. Treaties from 1819 to 1836 took most of the land, but many Anishinaabe negotiated to remain, avoiding removal. After the bloodless Toledo War traded Toledo for the Upper Peninsula, Michigan entered the Union in 1837."},
  {from:1837,to:1900,text:"Lumbermen stripped the white pine — Michigan led the nation in timber by the 1870s, leaving cutover stumplands and fire disasters. Keweenaw copper and Marquette iron ranges drew Cornish, Finnish, and Italian miners, and the 1855 Soo Locks moved the ore. Railroads, Grand Rapids furniture, stoves, and carriage shops built the industrial base the auto industry would inherit."},
  {from:1900,to:1950,text:"Ford's Model T (1908) and five-dollar day (1914) made Detroit the Motor City, magnet of the Great Migration and European immigration. The 1936-37 Flint sit-down strike forced GM to recognize the UAW. As the 'Arsenal of Democracy,' Willow Run turned out a bomber an hour, while wartime tensions exploded in Detroit's deadly 1943 race riot. Detroit peaked near 1.85 million people in 1950."},
  {from:1950,to:2026,text:"Freeways and white flight drained Detroit; the 1967 uprising left 43 dead, and in 2013 the city filed history's largest municipal bankruptcy before a downtown revival. Foreign competition shuttered plants statewide, and Flint's 2014 water crisis poisoned a majority-Black city. Twelve federally recognized tribes exercise 1836 treaty fishing rights; Michigan now stakes its future on EVs and the Great Lakes."}
 ],
 sources:["Michigan History Center","Detroit Historical Society","U.S. Census Bureau"]},
"27":{origin:"Northwest Territory east of the Mississippi, Louisiana Purchase west → Minnesota Territory (1849) → statehood 1858",namedFor:"Dakota 'Mni Sota Makoce' — land where the waters reflect the clouds",
 eras:[
  {from:1750,to:1849,text:"Dakota homeland centered on Bdote, the sacred junction of the Mississippi and Minnesota rivers; Ojibwe people, moving west with the fur trade, took the northern lakes in eighteenth-century wars. French and British traders married into Native families. Fort Snelling rose on Dakota land in 1820, and after the 1837 cession treaties lumbermen and settlers pressed in; Minnesota Territory was organized in 1849."},
  {from:1849,to:1863,text:"The 1851 treaties of Traverse des Sioux and Mendota took some 24 million Dakota acres, leaving a narrow reservation; statehood came in 1858. Starved by late annuities in 1862, Dakota fighters went to war, and hundreds of settlers died. Afterward 38 Dakota men were hanged at Mankato on December 26, 1862 — the largest mass execution in U.S. history — and the Dakota were interned at Fort Snelling, then exiled from the state."},
  {from:1863,to:1945,text:"Scandinavian and German homesteaders plowed the prairie; St. Anthony Falls made Minneapolis the world's flour-milling capital (Pillsbury, General Mills), and after 1890 the Mesabi Range shipped most of America's iron ore. Ojibwe bands kept northern reservations — Red Lake was never allotted — while losing timberland to fraud. Wartime ore fed the arsenals; the Mayo Clinic and 3M diversified the economy."},
  {from:1945,to:2026,text:"Taconite processing revived the Iron Range; corn and soybeans replaced wheat. The Twin Cities built a Fortune 500 cluster — Target, 3M, medical devices — and a strong social-democratic streak in the DFL of Humphrey and Mondale. Hmong refugees after 1975 and the nation's largest Somali community remade urban neighborhoods. George Floyd's 2020 murder by Minneapolis police ignited a global reckoning."}
 ],
 sources:["Minnesota Historical Society","U.S. Census Bureau"]},
"28":{origin:"French Louisiane → British West Florida (1763) → Mississippi Territory (1798) → statehood 1817",namedFor:"Ojibwe 'misi-ziibi' — 'great river' — carried south by French traders",
 eras:[
  {from:1750,to:1817,text:"Choctaw and Chickasaw homelands; France had destroyed the Natchez in the 1730s, selling survivors into slavery. Britain took the region in 1763, and Spain later held the coast. The Mississippi Territory (1798) drew cotton planters up the river roads. The Choctaw and Chickasaw sided with the United States against the Red Stick Creeks in 1813-14, but statehood in 1817 only sharpened demands for their land."},
  {from:1817,to:1865,text:"The 1830 Treaty of Dancing Rabbit Creek — the first removal treaty under Jackson's Indian Removal Act — took the Choctaw nation west, and thousands died on the road; Chickasaw removal followed in 1837-38. A remnant Choctaw community stayed and endured. Cotton made Mississippi rich and enslaved: 55 percent of its people were held as property by 1860. It seceded second, in January 1861; Vicksburg's fall in 1863 split the Confederacy."},
  {from:1865,to:1954,text:"Reconstruction sent the first Black U.S. senators, Revels and Bruce, from Mississippi — before the violent 1875 'Mississippi Plan' and the disenfranchising 1890 constitution became the South's template. Sharecropping bound the Delta, and lynchings led the nation. The 1927 flood and the boll weevil pushed the Great Migration north, carrying the Delta blues to Chicago. The Mississippi Band of Choctaw won federal recognition in 1945."},
  {from:1954,to:2026,text:"Emmett Till's 1955 lynching, Medgar Evers's 1963 assassination, and the 1964 Freedom Summer murders made Mississippi the movement's bloodiest ground; Black voter registration surged after 1965, and the state now elects among the most Black officials in the nation. Catfish ponds, poultry, Gulf shipyards, and casinos supplement farming, yet Mississippi remains the poorest state, with about 2.9 million people."}
 ],
 sources:["Mississippi Department of Archives and History","U.S. Census Bureau"]},
"29":{origin:"Louisiana Purchase (1803) → Missouri Territory (1812) → statehood 1821 under the Missouri Compromise",namedFor:"The Missouria (Niutachi) people — an Illinois-language name glossed 'people of the wooden canoes'",
 eras:[
  {from:1750,to:1803,text:"The Osage dominated the region's trade and diplomacy; the Missouria, ravaged by epidemics and war, dwindled and later merged with the Otoe. French habitants founded Ste. Genevieve (c. 1750) and the fur post of St. Louis (1764), living under nominal Spanish rule after 1762 — mining lead, farming, and trading with Native nations — until the 1803 Louisiana Purchase."},
  {from:1803,to:1865,text:"The 1808 Osage treaty stripped most of Missouri; the Osage were pushed into Kansas by 1825. The 1820 Missouri Compromise admitted Missouri as a slave state (1821), balanced by free Maine. St. Louis and Independence outfitted the Santa Fe and Oregon trails; the Dred Scott case began in the St. Louis courthouse. Mormons were expelled under an 1838 'extermination order,' and the Civil War brought savage guerrilla conflict; Missouri abolished slavery in January 1865."},
  {from:1865,to:1945,text:"German and Irish immigration made St. Louis the fourth-largest U.S. city by 1900 — brewing, shoes, and the 1904 World's Fair — while Kansas City boomed on stockyards, rail, and Pendergast-machine jazz. James-gang outlawry mythologized the war's wounds. Bootheel sharecroppers struck in 1939, and wartime plants making small arms and aircraft carried the state into the industrial age; Harry Truman went from Independence to the White House."},
  {from:1945,to:2026,text:"McDonnell (later Boeing) built Mercury and Gemini capsules and fighter jets in St. Louis, where the Gateway Arch rose in 1965 over a razed riverfront. St. Louis shrank from 857,000 people in 1950 to around 300,000, and the 2014 Ferguson protests over Michael Brown's killing sparked a national movement. Agriculture, aerospace, biotech, and logistics lead an economy of about 6.2 million Missourians."}
 ],
 sources:["State Historical Society of Missouri","Missouri State Archives","U.S. Census Bureau"]}
});
